def is_palindrome(s):
    s = s.lower().replace(' ', '')
    return s == s[::-1]

function debounce(fn, delay) {
  let timer;
  return function(...args) {
    clearTimeout(timer);
    timer = setTimeout(() => fn.apply(this, args), delay);
  };
}

class BST:
    def __init__(self, val=None):
        self.val = val
        self.left = None
        self.right = None

    def insert(self, val):
        if self.val is None:
            self.val = val
            return
        if val < self.val:
            if self.left:
                self.left.insert(val)
            else:
                self.left = BST(val)
        else:
            if self.right:
                self.right.insert(val)
            else:
                self.right = BST(val)

    def search(self, val):
        if self.val == val:
            return True
        if val < self.val and self.left:
            return self.left.search(val)
        if val > self.val and self.right:
            return self.right.search(val)
        return False

